const item = $input.first().json;
const validActions = ['opened', 'synchronize'];
const action = item.action || '';
const prNumber = item.pr_number;
const repoFullName = item.repo_full_name || '';
const headSha = item.head_sha || '';

const isValid = (
  validActions.includes(action) &&
  prNumber != null && prNumber > 0 &&
  repoFullName.includes('/') &&
  headSha.length > 0
);

return [{
  json: {
    ...item,
    is_valid_event: isValid,
    validation_reason: !isValid ? `Invalid: action=${action}, pr=${prNumber}, repo=${repoFullName}, sha=${headSha}` : 'ok'
  }
}];

// GitHub API returns an array; n8n httpRequest splits array responses into multiple items.
// Collect all file objects from step_4 output items.
const filesRaw = $input.all().map(i => i.json);

// Retrieve PR metadata from upstream named node (not from step_4's file items)
const meta = $('Validate PR Event Fields').first().json;

const MAX_PATCH_LINES = 400;
const MAX_TOTAL_CHARS = 8000;

let diffSections = [];
let totalChars = 0;

for (const file of filesRaw) {
  const filename = file.filename || 'unknown';
  const status = file.status || '';
  let patch = file.patch || '';

  // Truncate per-file patch
  const lines = patch.split('\n');
  if (lines.length > MAX_PATCH_LINES) {
    patch = lines.slice(0, MAX_PATCH_LINES).join('\n') + '\n[...truncated]';
  }

  const section = `### File: ${filename} (${status})\n${patch}`;

  if (totalChars + section.length > MAX_TOTAL_CHARS) {
    diffSections.push(`### File: ${filename} (${status})\n[diff omitted — total size limit reached]`);
    break;
  }

  diffSections.push(section);
  totalChars += section.length;
}

const fileCount = filesRaw.length;
const fileNames = filesRaw.map(f => f.filename).filter(Boolean).join(', ');

// Warn if we hit the pagination limit — some files may be missing
let paginationWarning = '';
if (fileCount >= 100) {
  paginationWarning = '\n\n> ⚠️ **Note:** This PR has 100+ changed files. The scan may be incomplete due to GitHub API pagination limits. Only the first 100 files were analyzed.';
  diffSections.push('\n### ⚠️ Pagination Warning\n[This PR has 100+ files. Results may be incomplete — only first 100 files were fetched from GitHub API.]');
}

const diffText = diffSections.join('\n\n');

return [{
  json: {
    repo_full_name: meta.repo_full_name,
    pr_number: meta.pr_number,
    pr_title: meta.pr_title,
    pr_html_url: meta.pr_html_url,
    head_sha: meta.head_sha,
    file_count: fileCount,
    file_names: fileNames,
    diff_text: diffText,
    diff_char_count: diffText.length,
    pagination_warning: paginationWarning
  }
}];

const item = $input.first().json;
const content = item.content || [];
const textBlock = content.find(c => c.type === 'text');
const llmText = (textBlock && textBlock.text) ? textBlock.text.trim() : '';
const isValid = llmText.length > 0;

return [{
  json: {
    llm_response_valid: isValid,
    llm_text: llmText,
    llm_raw: item
  }
}];

const item = $input.first().json;

// LLM text is already extracted by step_6b
const llmText = item.llm_text || '';

// Retrieve PR metadata from the upstream named node
const meta = $('Prepare Diff and Metadata for LLM').first().json;

// Parse JSON from LLM output — try full text first, then regex extraction
let report = null;
let parseError = null;
try {
  // First attempt: try to parse the entire trimmed text as JSON
  let toParse = llmText.trim();
  try {
    report = JSON.parse(toParse);
  } catch (e1) {
    // Second attempt: extract JSON object using non-greedy-friendly approach
    // Find first '{' and last '}' to extract outermost object
    const firstBrace = toParse.indexOf('{');
    const lastBrace = toParse.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      const candidate = toParse.slice(firstBrace, lastBrace + 1);
      report = JSON.parse(candidate);
    } else {
      throw new Error('No JSON object found in LLM response');
    }
  }
} catch(e) {
  parseError = e.message;
}

// If parse failed, signal infrastructure error — do NOT silently default to 'none'
if (!report || typeof report !== 'object') {
  return [{
    json: {
      repo_full_name: meta.repo_full_name || 'unknown',
      pr_number: meta.pr_number,
      pr_title: meta.pr_title || '',
      pr_html_url: meta.pr_html_url || '',
      head_sha: meta.head_sha || 'unknown',
      risk_level: 'parse_error',
      findings_count: 0,
      high_severity_count: 0,
      summary: 'Could not parse LLM response',
      false_positive_risk: 'unknown',
      should_escalate: false,
      should_comment: false,
      comment_body: '',
      parse_error: parseError,
      parse_failed: true
    }
  }];
}

// Validate and normalize
const validRiskLevels = ['none', 'low', 'medium', 'high'];
const riskLevel = validRiskLevels.includes(report.risk_level) ? report.risk_level : 'none';
const findings = Array.isArray(report.findings) ? report.findings : [];
const summary = typeof report.summary === 'string' ? report.summary : 'No summary provided';
const fpRisk = report.false_positive_risk || 'medium';

// High confidence findings only (filter out low confidence)
const highConfidenceFindings = findings.filter(f => f.confidence === 'high' || f.confidence === 'medium');
const highSeverityFindings = highConfidenceFindings.filter(f => f.severity === 'high');

// Escalate if risk level is high AND there are high-severity high/medium-confidence findings
const shouldEscalate = riskLevel === 'high' && highSeverityFindings.length > 0;

// Should post comment if any findings exist (non-none risk) OR if there are medium+ findings
const shouldComment = riskLevel !== 'none' && highConfidenceFindings.length > 0;

// Use PR metadata from named node reference
const repoFullName = meta.repo_full_name || 'unknown';
const prNumber = meta.pr_number;
const prTitle = meta.pr_title || '';
const prHtmlUrl = meta.pr_html_url || '';
const headSha = meta.head_sha || 'unknown';
const paginationWarning = meta.pagination_warning || '';

// Format findings as GitHub markdown comment
let commentBody = '';
if (shouldComment) {
  const findingLines = highConfidenceFindings.map(f => {
    const sev = f.severity === 'high' ? '🔴' : f.severity === 'medium' ? '🟡' : '🟢';
    return `| ${sev} ${f.severity.toUpperCase()} | ${f.category} | \`${f.file}\` | ${f.description} |`;
  }).join('\n');

  commentBody = `## 🔒 Security Scan Results\n\n**Risk Level:** \`${riskLevel.toUpperCase()}\`  \n**Summary:** ${summary}\n\n> ⚠️ This is an automated security pre-scan. It is non-blocking and for informational purposes only. All findings require human review.\n\n### Findings (${highConfidenceFindings.length} medium/high-confidence)\n\n| Severity | Category | File | Description |\n|---|---|---|---|\n${findingLines}\n\n*Scan performed on commit \`${headSha}\` | False positive risk: ${fpRisk}*${paginationWarning}`;
} else {
  commentBody = `## 🔒 Security Scan Results\n\n**Risk Level:** \`${riskLevel.toUpperCase()}\`  \n**Summary:** ${summary}\n\n✅ No medium/high-confidence security findings detected in this PR.\n\n*Scan performed on commit \`${headSha}\`*${paginationWarning}`;
}

return [{
  json: {
    repo_full_name: repoFullName,
    pr_number: prNumber,
    pr_title: prTitle,
    pr_html_url: prHtmlUrl,
    head_sha: headSha,
    risk_level: riskLevel,
    findings_count: highConfidenceFindings.length,
    high_severity_count: highSeverityFindings.length,
    summary: summary,
    false_positive_risk: fpRisk,
    should_escalate: shouldEscalate,
    should_comment: shouldComment,
    comment_body: commentBody,
    parse_error: parseError,
    parse_failed: false
  }
}];

